/**
 * Enhanced Fluent API for ForgeScript experiment building with TypeScript IntelliSense
 * and compile-time validation
 */

import { z } from 'zod';
import { Experiment, type ExperimentOptions } from '../core/Experiment.js';
import { Timeline } from '../core/Timeline.js';
import { TextStimulus } from '../stimuli/Text.js';
import { ImageStimulus } from '../stimuli/Image.js';
import { AudioStimulus } from '../stimuli/Audio.js';
import { VideoStimulus } from '../stimuli/Video.js';
import { KeyboardResponse } from '../responses/KeyboardResponse.js';
import { MouseResponse } from '../responses/MouseResponse.js';
import { TouchResponse } from '../responses/TouchResponse.js';
import { WaitEvent, LoopEvent, ConditionalEvent, DataEvent } from '../core/Event.js';
import { ForgeScriptCompiler, type CompilerOptions, type CompilerResult } from '../compiler/ForgeScriptCompiler.js';

// Power analysis types
export interface PowerAnalysisOptions {
  /** Effect size to detect */
  effectSize: number;
  /** Desired statistical power (default: 0.8) */
  power?: number;
  /** Significance level (default: 0.05) */
  alpha?: number;
  /** Type of statistical test */
  testType: 'ttest' | 'anova' | 'chi-square' | 'correlation' | 'regression';
  /** Number of groups/conditions */
  groups?: number;
  /** Expected variance */
  variance?: number;
}

export interface PowerAnalysisResult {
  /** Required sample size */
  sampleSize: number;
  /** Statistical power */
  power: number;
  /** Effect size */
  effectSize: number;
  /** Test configuration */
  testConfig: PowerAnalysisOptions;
  /** Recommendations */
  recommendations: string[];
}

// Type-safe condition builder
export interface ConditionBuilder<T = Record<string, unknown>> {
  /** Add a factor to the condition */
  factor<K extends string, V>(name: K, values: V[]): ConditionBuilder<T & Record<K, V>>;
  /** Set the number of repetitions per condition */
  repeat(count: number): ConditionBuilder<T>;
  /** Randomize condition order */
  randomize(seed?: number): ConditionBuilder<T>;
  /** Block conditions by factor */
  block<K extends keyof T>(factor: K): ConditionBuilder<T>;
  /** Build the condition list */
  build(): Array<T & { _trial: number; _block?: number }>;
}

// Type-safe trial builder
export interface TrialBuilder<TContext = Record<string, unknown>> {
  /** Add a fixation cross */
  fixation(duration?: number, symbol?: string): TrialBuilder<TContext>;
  /** Add text stimulus */
  text(content: string | ((ctx: TContext) => string), duration?: number): TrialBuilder<TContext>;
  /** Add image stimulus */
  image(url: string, duration?: number): TrialBuilder<TContext>;
  /** Add audio stimulus */
  audio(url: string): TrialBuilder<TContext>;
  /** Add video stimulus */
  video(url: string, duration?: number): TrialBuilder<TContext>;
  /** Add keyboard response collection */
  keyboard(keys?: string[], timeout?: number): TrialBuilder<TContext>;
  /** Add mouse response collection */
  mouse(timeout?: number): TrialBuilder<TContext>;
  /** Add touch response collection */
  touch(timeout?: number): TrialBuilder<TContext>;
  /** Add a wait/delay */
  wait(duration: number): TrialBuilder<TContext>;
  /** Add conditional logic */
  when(condition: (ctx: TContext) => boolean, then: (builder: TrialBuilder<TContext>) => void): TrialBuilder<TContext>;
  /** Add a loop */
  loop(count: number | ((ctx: TContext) => number), body: (builder: TrialBuilder<TContext>) => void): TrialBuilder<TContext>;
  /** Set trial-level data */
  setData<K extends string, V>(key: K, value: V | ((ctx: TContext) => V)): TrialBuilder<TContext & Record<K, V>>;
  /** Build the trial timeline */
  build(): Timeline;
}

// Validation schemas for compile-time checking
const ExperimentConfigSchema = z.object({
  title: z.string().min(1, 'Title is required'),
  description: z.string().optional(),
  version: z.string().regex(/^\d+\.\d+\.\d+$/, 'Version must follow semantic versioning (e.g., 1.0.0)'),
  author: z.string().optional(),
  institution: z.string().optional(),
  tags: z.array(z.string()).optional(),
});

const PowerAnalysisSchema = z.object({
  effectSize: z.number().positive('Effect size must be positive'),
  power: z.number().min(0.1).max(0.99).optional(),
  alpha: z.number().min(0.001).max(0.1).optional(),
  testType: z.enum(['ttest', 'anova', 'chi-square', 'correlation', 'regression']),
  groups: z.number().int().min(1).optional(),
  variance: z.number().positive().optional(),
});

export class FluentExperimentBuilder {
  private experimentOptions: ExperimentOptions = {};
  private timelines: Timeline[] = [];
  private powerAnalysis?: PowerAnalysisOptions;
  private compilerOptions: CompilerOptions = {};

  constructor(id: string) {
    this.experimentOptions.metadata = {
      title: id,
      version: '1.0.0',
      created: Date.now(),
      modified: Date.now(),
      psychoforgeVersion: '1.0.0',
    };
  }

  // Experiment metadata fluent API with validation
  title(title: string): this {
    const validated = z.string().min(1, 'Title cannot be empty').parse(title);
    this.experimentOptions.metadata = {
      ...this.experimentOptions.metadata,
      title: validated,
      modified: Date.now(),
    };
    return this;
  }

  description(description: string): this {
    const validated = z.string().min(1, 'Description cannot be empty').parse(description);
    this.experimentOptions.metadata = {
      ...this.experimentOptions.metadata,
      description: validated,
      modified: Date.now(),
    };
    return this;
  }

  version(version: string): this {
    const validated = z.string()
      .regex(/^\d+\.\d+\.\d+$/, 'Version must follow semantic versioning (e.g., 1.0.0)')
      .parse(version);
    this.experimentOptions.metadata = {
      ...this.experimentOptions.metadata,
      version: validated,
      modified: Date.now(),
    };
    return this;
  }

  author(author: string): this {
    const validated = z.string().min(1, 'Author cannot be empty').parse(author);
    this.experimentOptions.metadata = {
      ...this.experimentOptions.metadata,
      author: validated,
      modified: Date.now(),
    };
    return this;
  }

  institution(institution: string): this {
    const validated = z.string().min(1, 'Institution cannot be empty').parse(institution);
    this.experimentOptions.metadata = {
      ...this.experimentOptions.metadata,
      institution: validated,
      modified: Date.now(),
    };
    return this;
  }

  tags(tags: string[]): this {
    const validated = z.array(z.string().min(1, 'Tag cannot be empty')).parse(tags);
    this.experimentOptions.metadata = {
      ...this.experimentOptions.metadata,
      tags: validated,
      modified: Date.now(),
    };
    return this;
  }

  // Power analysis integration
  requirePower(options: PowerAnalysisOptions): this {
    // Validate power analysis options at compile time
    const validated = PowerAnalysisSchema.parse(options);
    this.powerAnalysis = validated;
    return this;
  }

  // Calculate required sample size based on power analysis
  calculateSampleSize(): PowerAnalysisResult {
    if (!this.powerAnalysis) {
      throw new Error('Power analysis not configured. Call requirePower() first.');
    }

    const config = this.powerAnalysis;
    const power = config.power || 0.8;
    // Alpha level would be used in full power analysis implementation
    // const alpha = config.alpha || 0.05;

    // Simplified power analysis calculations
    // In a real implementation, this would use proper statistical formulas
    let sampleSize: number;
    const recommendations: string[] = [];

    switch (config.testType) {
      case 'ttest':
        // Cohen's d effect size for t-test
        sampleSize = Math.ceil(16 / (config.effectSize * config.effectSize));
        if (config.effectSize < 0.2) {
          recommendations.push('Small effect size detected. Consider increasing sample size for better power.');
        }
        break;

      case 'anova':
        const groups = config.groups || 2;
        sampleSize = Math.ceil((groups * 16) / (config.effectSize * config.effectSize));
        recommendations.push(`ANOVA with ${groups} groups. Consider counterbalancing if possible.`);
        break;

      case 'correlation':
        sampleSize = Math.ceil(8 / (config.effectSize * config.effectSize) + 3);
        if (sampleSize < 30) {
          recommendations.push('Consider minimum sample size of 30 for correlation analysis.');
        }
        break;

      case 'chi-square':
        sampleSize = Math.ceil(16 / (config.effectSize * config.effectSize));
        recommendations.push('Ensure expected cell frequencies are at least 5 for chi-square test.');
        break;

      case 'regression':
        const predictors = config.groups || 1;
        sampleSize = Math.ceil(104 + predictors);
        recommendations.push(`Multiple regression with ${predictors} predictor(s). Follow 10:1 rule for stable estimates.`);
        break;

      default:
        throw new Error(`Unsupported test type: ${config.testType}`);
    }

    // Adjust for desired power
    const powerAdjustment = Math.log(power / (1 - power)) / Math.log(4);
    sampleSize = Math.ceil(sampleSize * (1 + powerAdjustment));

    // Minimum sample size recommendations
    if (sampleSize < 20) {
      recommendations.push('Consider minimum sample size of 20 for reliable results.');
      sampleSize = Math.max(sampleSize, 20);
    }

    return {
      sampleSize,
      power,
      effectSize: config.effectSize,
      testConfig: config,
      recommendations,
    };
  }

  // Type-safe condition builder
  conditions<T = Record<string, unknown>>(): ConditionBuilder<T> {
    return new ConditionBuilderImpl<T>();
  }

  // Type-safe trial builder
  trial<TContext = Record<string, unknown>>(): TrialBuilder<TContext> {
    return new TrialBuilderImpl<TContext>();
  }

  // Add timeline to experiment
  addTimeline(timeline: Timeline): this {
    this.timelines.push(timeline);
    return this;
  }

  // Experiment options
  fullScreen(enabled: boolean = true): this {
    this.experimentOptions.fullScreen = enabled;
    return this;
  }

  backgroundColor(color: string): this {
    // Basic color validation
    const colorRegex = /^(#[0-9a-fA-F]{3,8}|rgb\(.*\)|rgba\(.*\)|hsl\(.*\)|hsla\(.*\)|[a-zA-Z]+)$/;
    if (!colorRegex.test(color)) {
      throw new Error(`Invalid color format: ${color}`);
    }
    this.experimentOptions.backgroundColor = color;
    return this;
  }

  cursor(cursorType: string): this {
    const validCursors = [
      'auto', 'default', 'none', 'pointer', 'wait', 'text', 'crosshair', 'move', 'help'
    ];
    if (!validCursors.includes(cursorType)) {
      throw new Error(`Invalid cursor type: ${cursorType}. Must be one of: ${validCursors.join(', ')}`);
    }
    this.experimentOptions.cursor = cursorType;
    return this;
  }

  // Compiler options
  strict(enabled: boolean = true): this {
    this.compilerOptions.strict = enabled;
    return this;
  }

  optimize(enabled: boolean = true): this {
    this.compilerOptions.optimize = enabled;
    return this;
  }

  enableVerification(enabled: boolean = true): this {
    this.compilerOptions.enableVerification = enabled;
    return this;
  }

  includeDebugInfo(enabled: boolean = true): this {
    this.compilerOptions.includeDebugInfo = enabled;
    return this;
  }

  // Build and validate experiment
  build(): Experiment {
    // Validate experiment configuration
    if (this.experimentOptions.metadata) {
      ExperimentConfigSchema.parse(this.experimentOptions.metadata);
    }

    if (this.timelines.length === 0) {
      throw new Error('Experiment must have at least one timeline. Use trial() or addTimeline() to add content.');
    }

    // Create experiment
    const experiment = new Experiment('built-experiment', this.experimentOptions);
    experiment.timeline(this.timelines);

    return experiment;
  }

  // Compile to FZB binary format
  async compile(): Promise<CompilerResult> {
    const experiment = this.build();
    const compiler = new ForgeScriptCompiler(this.compilerOptions);
    return compiler.compile(experiment);
  }

  // Validate without building
  validate(): { valid: boolean; errors: string[] } {
    const errors: string[] = [];

    try {
      // Validate metadata
      if (this.experimentOptions.metadata) {
        ExperimentConfigSchema.parse(this.experimentOptions.metadata);
      }
    } catch (error) {
      if (error instanceof z.ZodError) {
        errors.push(...error.errors.map(e => e.message));
      }
    }

    // Check for timelines
    if (this.timelines.length === 0) {
      errors.push('Experiment must have at least one timeline');
    }

    // Validate power analysis if present
    if (this.powerAnalysis) {
      try {
        PowerAnalysisSchema.parse(this.powerAnalysis);
      } catch (error) {
        if (error instanceof z.ZodError) {
          errors.push(...error.errors.map(e => `Power analysis: ${e.message}`));
        }
      }
    }

    return {
      valid: errors.length === 0,
      errors,
    };
  }

  // Create common experiment patterns
  static stroopTask(): FluentExperimentBuilder {
    return new FluentExperimentBuilder('stroop-task')
      .title('Stroop Task')
      .description('Classic Stroop color-word interference task')
      .version('1.0.0')
      .tags(['attention', 'cognitive-control', 'stroop']);
  }

  static simpleRT(): FluentExperimentBuilder {
    return new FluentExperimentBuilder('simple-rt')
      .title('Simple Reaction Time')
      .description('Simple reaction time measurement task')
      .version('1.0.0')
      .tags(['reaction-time', 'simple-rt']);
  }

  static choiceRT(): FluentExperimentBuilder {
    return new FluentExperimentBuilder('choice-rt')
      .title('Choice Reaction Time')
      .description('Choice reaction time with multiple response options')
      .version('1.0.0')
      .tags(['reaction-time', 'choice-rt', 'decision-making']);
  }
}

// Implementation classes for builders
class ConditionBuilderImpl<T = Record<string, unknown>> implements ConditionBuilder<T> {
  private factors: Record<string, unknown[]> = {};
  private repetitions = 1;
  private shouldRandomize = false;
  private randomSeed?: number;
  private blockingFactor?: string;

  factor<K extends string, V>(name: K, values: V[]): ConditionBuilder<T & Record<K, V>> {
    if (values.length === 0) {
      throw new Error(`Factor '${name}' must have at least one value`);
    }
    this.factors[name] = values;
    return this as any;
  }

  repeat(count: number): ConditionBuilder<T> {
    if (count < 1) {
      throw new Error('Repeat count must be at least 1');
    }
    this.repetitions = count;
    return this;
  }

  randomize(seed?: number): ConditionBuilder<T> {
    this.shouldRandomize = true;
    this.randomSeed = seed;
    return this;
  }

  block<K extends keyof T>(factor: K): ConditionBuilder<T> {
    this.blockingFactor = factor as string;
    return this;
  }

  build(): Array<T & { _trial: number; _block?: number }> {
    // Generate all combinations
    const factorNames = Object.keys(this.factors);
    if (factorNames.length === 0) {
      throw new Error('At least one factor must be defined');
    }

    const combinations = this.generateCombinations(factorNames, this.factors);

    // Repeat combinations
    const conditions: Array<T & { _trial: number; _block?: number }> = [];
    for (let rep = 0; rep < this.repetitions; rep++) {
      combinations.forEach((combo) => {
        conditions.push({
          ...combo,
          _trial: conditions.length,
        } as T & { _trial: number; _block?: number });
      });
    }

    // Apply blocking
    if (this.blockingFactor && this.blockingFactor in this.factors) {
      this.applyBlocking(conditions, this.blockingFactor);
    }

    // Randomize if requested
    if (this.shouldRandomize) {
      this.randomizeConditions(conditions, this.randomSeed);
    }

    return conditions;
  }

  private generateCombinations(factorNames: string[], factors: Record<string, unknown[]>): T[] {
    const result: T[] = [];

    const generate = (index: number, current: Record<string, unknown>) => {
      if (index === factorNames.length) {
        result.push(current as T);
        return;
      }

      const factorName = factorNames[index];
      if (!factorName) return;

      const values = factors[factorName];
      if (!values) return;

      for (const value of values) {
        generate(index + 1, { ...current, [factorName]: value });
      }
    };

    generate(0, {});
    return result;
  }

  private applyBlocking(conditions: Array<T & { _trial: number; _block?: number }>, blockingFactor: string): void {
    const blocks = new Map<unknown, number>();
    let blockIndex = 0;

    conditions.forEach(condition => {
      const blockValue = (condition as any)[blockingFactor];
      if (!blocks.has(blockValue)) {
        blocks.set(blockValue, blockIndex++);
      }
      condition._block = blocks.get(blockValue);
    });
  }

  private randomizeConditions(conditions: Array<T & { _trial: number; _block?: number }>, seed?: number): void {
    // Simple pseudo-random shuffle
    // In a real implementation, this would use a proper seeded random number generator
    const rng = seed ? this.seededRandom(seed) : Math.random;

    for (let i = conditions.length - 1; i > 0; i--) {
      const j = Math.floor(rng() * (i + 1));
      const temp = conditions[i];
      conditions[i] = conditions[j]!;
      conditions[j] = temp!;
    }

    // Update trial numbers
    conditions.forEach((condition, index) => {
      condition._trial = index;
    });
  }

  private seededRandom(seed: number): () => number {
    return () => {
      seed = (seed * 9301 + 49297) % 233280;
      return seed / 233280;
    };
  }
}

class TrialBuilderImpl<TContext = Record<string, unknown>> implements TrialBuilder<TContext> {
  private timeline: Timeline;

  constructor() {
    this.timeline = new Timeline(`trial-${Date.now()}`);
  }

  fixation(duration: number = 1000, symbol: string = '+'): TrialBuilder<TContext> {
    const stimulus = new TextStimulus(`fixation-${Date.now()}`, symbol, {
      fontSize: 48,
      color: 'black',
      position: { x: 0, y: 0 },
      duration,
    });
    this.timeline.add(stimulus);
    return this;
  }

  text(content: string | ((ctx: TContext) => string), duration?: number): TrialBuilder<TContext> {
    const stimulus = new TextStimulus(`text-${Date.now()}`, content as any, {
      fontSize: 24,
      color: 'black',
      position: { x: 0, y: 0 },
      duration,
    });
    this.timeline.add(stimulus);
    return this;
  }

  image(url: string, duration?: number): TrialBuilder<TContext> {
    const stimulus = new ImageStimulus(`image-${Date.now()}`, url, {
      duration,
      position: { x: 0, y: 0 },
    });
    this.timeline.add(stimulus);
    return this;
  }

  audio(url: string): TrialBuilder<TContext> {
    const stimulus = new AudioStimulus(`audio-${Date.now()}`, url, {
      autoplay: true,
    });
    this.timeline.add(stimulus);
    return this;
  }

  video(url: string, duration?: number): TrialBuilder<TContext> {
    const stimulus = new VideoStimulus(`video-${Date.now()}`, url, {
      duration,
      autoplay: true,
      position: { x: 0, y: 0 },
    });
    this.timeline.add(stimulus);
    return this;
  }

  keyboard(keys?: string[], timeout?: number): TrialBuilder<TContext> {
    const response = new KeyboardResponse(`keyboard-${Date.now()}`, {
      allowedKeys: keys,
      timeout,
    });
    this.timeline.addItem(response);
    return this;
  }

  mouse(timeout?: number): TrialBuilder<TContext> {
    const response = new MouseResponse(`mouse-${Date.now()}`, {
      timeout,
    });
    this.timeline.addItem(response);
    return this;
  }

  touch(timeout?: number): TrialBuilder<TContext> {
    const response = new TouchResponse(`touch-${Date.now()}`, {
      timeout,
    });
    this.timeline.addItem(response);
    return this;
  }

  wait(duration: number): TrialBuilder<TContext> {
    const waitEvent = new WaitEvent(`wait-${Date.now()}`, { duration });
    this.timeline.add(waitEvent);
    return this;
  }

  when(condition: (ctx: TContext) => boolean, then: (builder: TrialBuilder<TContext>) => void): TrialBuilder<TContext> {
    const conditionalEvent = new ConditionalEvent(`conditional-${Date.now()}`, {
      condition: condition as any,
      onTrue: () => {
        const subBuilder = new TrialBuilderImpl<TContext>();
        then(subBuilder);
        return subBuilder.build();
      },
    });
    this.timeline.add(conditionalEvent);
    return this;
  }

  loop(count: number | ((ctx: TContext) => number), body: (builder: TrialBuilder<TContext>) => void): TrialBuilder<TContext> {
    const loopEvent = new LoopEvent(`loop-${Date.now()}`, {
      count: count as any,
      body: () => {
        const subBuilder = new TrialBuilderImpl<TContext>();
        body(subBuilder);
        return subBuilder.build();
      },
    });
    this.timeline.add(loopEvent);
    return this;
  }

  setData<K extends string, V>(key: K, value: V | ((ctx: TContext) => V)): TrialBuilder<TContext & Record<K, V>> {
    const dataEvent = new DataEvent(`data-${Date.now()}`, {
      key,
      value: value as any,
    });
    this.timeline.add(dataEvent);
    return this as any;
  }

  build(): Timeline {
    return this.timeline;
  }
}

// Export convenience function
export function experiment(id: string): FluentExperimentBuilder {
  return new FluentExperimentBuilder(id);
}

// Export type-safe condition and trial builders
export function conditions<T = Record<string, unknown>>(): ConditionBuilder<T> {
  return new ConditionBuilderImpl<T>();
}

export function trial<TContext = Record<string, unknown>>(): TrialBuilder<TContext> {
  return new TrialBuilderImpl<TContext>();
}

