import { z } from 'zod';
import type { TimelineItem, TimelineContext } from '../core/Timeline.js';
import { 
  sanitizeColorValue, 
  sanitizeFontFamily, 
  sanitizeClassName, 
  sanitizeStyleValue, 
  sanitizeTextContent, 
  sanitizeNumericValue 
} from '../utils/security.js';

export interface TextStimulusOptions {
  duration?: number;
  position?: { x: number; y: number };
  fontSize?: number;
  fontFamily?: string;
  color?: string;
  backgroundColor?: string;
  opacity?: number;
  rotation?: number;
  scale?: number;
  zIndex?: number;
  className?: string;
  style?: Record<string, string>;
  metadata?: Record<string, unknown>;
}

export class TextStimulus implements TimelineItem {
  public readonly id: string;
  private textContent: string | ((context: TimelineContext) => string);
  private options: TextStimulusOptions;
  private element?: HTMLElement;

  constructor(
    id: string,
    text: string | ((context: TimelineContext) => string),
    options: TextStimulusOptions = {}
  ) {
    this.id = id;
    this.textContent = text;
    this.options = options;
  }

  text(content: string | ((context: TimelineContext) => string)): this {
    this.textContent = content;
    return this;
  }

  duration(ms: number): this {
    this.options.duration = ms;
    return this;
  }

  position(x: number, y: number): this {
    this.options.position = { x, y };
    return this;
  }

  fontSize(size: number): this {
    this.options.fontSize = size;
    return this;
  }

  fontFamily(family: string): this {
    const sanitized = sanitizeFontFamily(family);
    if (sanitized) {
      this.options.fontFamily = sanitized;
    }
    return this;
  }

  color(textColor: string): this {
    const sanitized = sanitizeColorValue(textColor);
    if (sanitized) {
      this.options.color = sanitized;
    }
    return this;
  }

  backgroundColor(bgColor: string): this {
    const sanitized = sanitizeColorValue(bgColor);
    if (sanitized) {
      this.options.backgroundColor = sanitized;
    }
    return this;
  }

  opacity(alpha: number): this {
    this.options.opacity = Math.max(0, Math.min(1, alpha));
    return this;
  }

  rotation(degrees: number): this {
    this.options.rotation = degrees;
    return this;
  }

  scale(factor: number): this {
    this.options.scale = factor;
    return this;
  }

  zIndex(z: number): this {
    this.options.zIndex = z;
    return this;
  }

  className(name: string): this {
    const sanitized = sanitizeClassName(name);
    if (sanitized) {
      this.options.className = sanitized;
    }
    return this;
  }

  style(styles: Record<string, string>): this {
    const sanitizedStyles: Record<string, string> = {};

    for (const [property, value] of Object.entries(styles)) {
      const sanitizedValue = sanitizeStyleValue(property, value);
      if (sanitizedValue) {
        sanitizedStyles[property] = sanitizedValue;
      }
    }

