/**
 * Backward Compatibility Layer for ForgeScript
 * 
 * Provides seamless migration from the existing fluent API to the new component system
 * while maintaining 100% backward compatibility for existing experiments.
 */

import { Timeline, type TimelineItem, type TimelineContext } from './core/Timeline.js';
import { TextStimulus } from './stimuli/Text.js';
import { KeyboardResponse } from './responses/KeyboardResponse.js';
import { ForgeBuilder, createForgeWithDefaults } from './ForgeBuilder.js';
import { ComponentSystem } from './components/ComponentSystem.js';
import { BaseComponent } from './components/BaseComponent.js';

/**
 * Component wrapper for legacy TimelineItem objects
 * Allows existing stimuli/responses to work in the new component system
 */
export class LegacyTimelineItemComponent extends BaseComponent {
  private timelineItem: TimelineItem;
  private isExecuting = false;

  constructor(timelineItem: TimelineItem) {
    super(timelineItem.id, 'LegacyTimelineItem');
    this.timelineItem = timelineItem;
    this.setUserData('legacyItem', timelineItem);
    this.tag('legacy', 'compatibility');
  }

  async onInit(_context: any): Promise<void> {
    // Legacy items are initialized when executed
  }

  onFrame(_deltaTime: number, _context: any): void {
    // Legacy items handle their own timing
  }

  async onDispose(_context: any): Promise<void> {
    // Legacy items handle their own cleanup
  }

  // Execute the legacy timeline item using the new context
  async executeLegacyItem(context: any): Promise<void> {
    if (this.isExecuting) {
      return;
    }

    this.isExecuting = true;
    try {
      // Convert new context to legacy timeline context
      const legacyContext: TimelineContext = {
        clock: context.clock,
        scheduler: context.scheduler,
        data: context.data,
        trial: context.trial,
        block: context.block,
      };

      await this.timelineItem.execute(legacyContext);
    } finally {
      this.isExecuting = false;
    }
  }

  getLegacyItem(): TimelineItem {
    return this.timelineItem;
  }
}

/**
 * Enhanced Timeline that can work with both legacy items and new components
 */
export class HybridTimeline extends Timeline {
  private componentSystem?: ComponentSystem;

  constructor(id: string, options: any = {}) {
    super(id, options);
  }

  setComponentSystem(system: ComponentSystem): void {
    this.componentSystem = system;
  }

  async execute(context: TimelineContext): Promise<void> {
    if (this.componentSystem) {
      // Execute using the new component system
      await this.executeWithComponents(context);
    } else {
      // Fallback to legacy execution
      await super.execute(context);
    }
  }

  private async executeWithComponents(context: TimelineContext): Promise<void> {
    const items = this.getItems();

    for (const item of items) {
      if (item instanceof BaseComponent) {
        // New component - add to system and wait for completion
        await this.componentSystem!.add(item);

        // Wait for component completion if it has a duration
        if ('duration' in item && typeof item.duration === 'number') {
          await new Promise(resolve => setTimeout(resolve, item.duration as number));
        }

        this.componentSystem!.remove(item);
      } else {
        // Legacy item - wrap in component adapter
        const wrapper = new LegacyTimelineItemComponent(item);
        await this.componentSystem!.add(wrapper);
        await wrapper.executeLegacyItem(context);
        this.componentSystem!.remove(wrapper);
      }
    }
  }
}

/**
 * Migration utilities for converting legacy experiments to component system
 */
export class ExperimentMigrator {
  static async migrateTimeline(timeline: Timeline, forge: ForgeBuilder): Promise<void> {
    const items = timeline.getItems();

    for (const item of items) {
      if (item instanceof TextStimulus) {
        // Convert TextStimulus to TextComponent
        const component = forge.text(
          typeof (item as any).textContent === 'function' 
            ? (item as any).textContent 
            : (item as any).textContent || ''
        );

        // Copy options from legacy stimulus
        const options = (item as any).options;
        if (options.duration) component.duration(options.duration);
        if (options.position) component.position(options.position.x, options.position.y);
        if (options.fontSize) component.fontSize(options.fontSize);
        if (options.fontFamily) component.fontFamily(options.fontFamily);
        if (options.color) component.color(options.color);
        if (options.backgroundColor) component.backgroundColor(options.backgroundColor);
        if (options.opacity !== undefined) component.opacity(options.opacity);
        if (options.rotation !== undefined) component.rotate(options.rotation);
        if (options.scale !== undefined) component.scale(options.scale);

        await forge.getSystem().add(component);

      } else if (item instanceof KeyboardResponse) {
        // Convert KeyboardResponse to KeyboardComponent
        const options = (item as any).options;
        const component = forge.keyboard({
          allowedKeys: options.allowedKeys,
          timeout: options.timeout,
          firstKeyOnly: options.firstKeyOnly,
        });

        await forge.getSystem().add(component);
      }
      // Add more legacy item conversions as needed
    }
  }

  static createHybridExperiment(
    legacyExperiment: any,
    container: HTMLElement | string
  ): Promise<ForgeBuilder> {
    // Create a ForgeBuilder that can run legacy experiments
    return createForgeWithDefaults(container, {
      enableMetrics: true,
      maxFrameTime: 2,
    });
  }
}

