  // Example 1: Existing experiment that uses legacy API continues to work
  async runLegacyExperiment() {
    const { ForgeScript } = await import('./index.js');

    // This is existing legacy code that should continue working
    const experiment = ForgeScript.createStroop(['RED', 'GREEN', 'BLUE'], ['red', 'green', 'blue'], 10);

    // Run with legacy runtime
    await ForgeScript.runExperiment(experiment, 'participant-001');
  },

