/**
 * ForgeScript Compiler - Compile-time validation and FZB binary format generation
 */

import { z } from 'zod';
import type { Experiment } from '../core/Experiment.js';
import type { Timeline } from '../core/Timeline.js';
import { Validator, type ValidationResult } from '../serialization/Validator.js';
import { Serializer } from '../serialization/Serializer.js';

export interface CompilerOptions {
  /** Enable strict type checking */
  strict?: boolean;
  /** Target FZB binary format version */
  targetVersion?: string;
  /** Enable optimization passes */
  optimize?: boolean;
  /** Enable formal verification */
  enableVerification?: boolean;
  /** Include debug information */
  includeDebugInfo?: boolean;
  /** Maximum compilation time in milliseconds */
  timeout?: number;
}

export interface CompilerResult {
  /** Whether compilation succeeded */
  success: boolean;
  /** Validation result from compiler */
  validation: ValidationResult;
  /** Compiled FZB binary data */
  binary?: Uint8Array;
  /** Compilation metadata */
  metadata?: CompilerMetadata;
  /** Compilation errors */
  errors: CompilerError[];
  /** Compilation warnings */
  warnings: CompilerWarning[];
}

export interface CompilerMetadata {
  /** Compilation timestamp */
  compiledAt: number;
  /** Compiler version */
  compilerVersion: string;
  /** Target FZB version */
  targetVersion: string;
  /** Source experiment hash */
  sourceHash: string;
  /** Optimization level applied */
  optimizationLevel: number;
  /** Size of compiled binary */
  binarySize: number;
}

export interface CompilerError {
  code: string;
  message: string;
  severity: 'critical' | 'high' | 'medium' | 'low';
  location?: string;
  suggestion?: string;
}

export interface CompilerWarning {
  code: string;
  message: string;
  location?: string;
  recommendation?: string;
}

export interface FZBHeader {
  /** Magic bytes "FZB\0" */
  magic: Uint8Array;
  /** FZB format version */
  version: number;
  /** Flags for format features */
  flags: number;
  /** Size of metadata section */
  metadataSize: number;
  /** Size of experiment data section */
  dataSize: number;
  /** CRC32 checksum */
  checksum: number;
}

export class ForgeScriptCompiler {
  private static readonly VERSION = '1.0.0';
  private static readonly FZB_MAGIC = new Uint8Array([0x46, 0x5A, 0x42, 0x00]); // "FZB\0"
  private static readonly FZB_VERSION = 1;

  private options: Required<CompilerOptions>;

  constructor(options: CompilerOptions = {}) {
    this.options = {
      strict: false,
      targetVersion: '1.0.0',
      optimize: true,
      enableVerification: false,
      includeDebugInfo: false,
      timeout: 30000, // 30 seconds
      ...options,
    };
  }

  /**
   * Compile an experiment to FZB binary format
   */
  async compile(experiment: Experiment): Promise<CompilerResult> {
    const startTime = Date.now();
    const errors: CompilerError[] = [];
    const warnings: CompilerWarning[] = [];

    try {
      // Set compilation timeout
      const timeoutPromise = new Promise<never>((_, reject) => {
        setTimeout(() => reject(new Error('Compilation timeout')), this.options.timeout);
      });

      const compilationPromise = this.performCompilation(experiment, errors, warnings);

      const result = await Promise.race([compilationPromise, timeoutPromise]);

      return {
        ...result,
        errors,
        warnings,
      };

    } catch (error) {
      errors.push({
        code: 'COMPILATION_FAILED',
        message: `Compilation failed: ${error}`,
        severity: 'critical',
      });

      return {
        success: false,
        validation: { valid: false, errors: [], warnings: [] },
        errors,
        warnings,
      };
    }
  }

  private async performCompilation(
    experiment: Experiment,
    errors: CompilerError[],
    warnings: CompilerWarning[]
  ): Promise<Omit<CompilerResult, 'errors' | 'warnings'>> {
    // Step 1: Validate experiment structure
    console.log('🔍 Validating experiment structure...');
    const validation = await this.validateExperiment(experiment);

    if (!validation.valid) {
      // Convert validation errors to compiler errors
      validation.errors.forEach(error => {
        errors.push({
          code: error.code,
          message: error.message,
          severity: error.severity,
          location: error.path,
        });
      });
    }

    // Convert validation warnings to compiler warnings
    validation.warnings.forEach(warning => {
      warnings.push({
        code: warning.code,
        message: warning.message,
        location: warning.path,
        recommendation: warning.recommendation,
      });
    });

    // Stop compilation if critical errors found in strict mode
    if (this.options.strict && errors.some(e => e.severity === 'critical')) {
      return {
        success: false,
        validation,
      };
    }

    // Step 2: Perform formal verification if enabled
    if (this.options.enableVerification) {
      console.log('✅ Performing formal verification...');
      await this.performFormalVerification(experiment, errors, warnings);
    }

    // Step 3: Optimize experiment if enabled
    let optimizedExperiment = experiment;
    if (this.options.optimize) {
      console.log('⚡ Optimizing experiment...');
      optimizedExperiment = await this.optimizeExperiment(experiment, warnings);
    }

    // Step 4: Generate FZB binary
    console.log('🔧 Generating FZB binary...');
    const binary = await this.generateFZBBinary(optimizedExperiment);

    // Step 5: Create compilation metadata
    const sourceHash = await this.computeHash(JSON.stringify(experiment.serialize()));
    const metadata: CompilerMetadata = {
      compiledAt: Date.now(),
      compilerVersion: ForgeScriptCompiler.VERSION,
      targetVersion: this.options.targetVersion,
      sourceHash,
      optimizationLevel: this.options.optimize ? 1 : 0,
      binarySize: binary.length,
    };

    console.log(`✨ Compilation completed successfully (${binary.length} bytes)`);

    return {
      success: true,
      validation,
      binary,
      metadata,
    };
  }

  private async validateExperiment(experiment: Experiment): Promise<ValidationResult> {
    const options = {
      strict: this.options.strict,
      checkTiming: true,
      checkAccessibility: true,
      checkPerformance: true,
    };

    return Validator.validateExperiment(experiment, options);
  }

  private async performFormalVerification(
    experiment: Experiment,
    errors: CompilerError[],
    warnings: CompilerWarning[]
  ): Promise<void> {
    // Formal verification checks
    const timelines = experiment.getTimelines();

    // Check for unreachable timelines
    const reachableTimelines = new Set<string>();
    this.markReachableTimelines(timelines, reachableTimelines);

    timelines.forEach((timeline, index) => {
      if (!reachableTimelines.has(timeline.id)) {
        warnings.push({
          code: 'UNREACHABLE_TIMELINE',
          message: `Timeline '${timeline.id}' is unreachable`,
          location: `timelines[${index}]`,
          recommendation: 'Remove unreachable timeline or fix timeline flow',
        });
      }
    });

    // Check for infinite loops
    this.detectInfiniteLoops(timelines, errors);

    // Check for missing dependencies
    this.validateDependencies(experiment, errors);

    // Check for timing constraints
    this.validateTimingConstraints(experiment, errors, warnings);
  }

  private markReachableTimelines(timelines: Timeline[], reachable: Set<string>): void {
    // Mark first timeline as reachable
