  private async generateFZBBinary(experiment: Experiment): Promise<Uint8Array> {
    // Serialize experiment to JSON
    const serialized = Serializer.serialize(experiment, {
      format: 'compact',
      includeMetadata: true,
      includeResponseData: false,
    });

    // Compress the JSON data
    const jsonData = JSON.stringify(serialized);
    const compressedData = await this.compressData(jsonData);

    // Create FZB header
    const header = this.createFZBHeader(compressedData);

    // Combine header and data
    const headerBytes = this.serializeHeader(header);
    const binary = new Uint8Array(headerBytes.length + compressedData.length);
    binary.set(headerBytes, 0);
    binary.set(compressedData, headerBytes.length);

    return binary;
  }

  private createFZBHeader(data: Uint8Array): FZBHeader {
    return {
      magic: ForgeScriptCompiler.FZB_MAGIC,
      version: ForgeScriptCompiler.FZB_VERSION,
      flags: this.options.includeDebugInfo ? 1 : 0,
      metadataSize: 0, // No separate metadata section for now
      dataSize: data.length,
      checksum: this.calculateCRC32(data),
    };
  }

  private serializeHeader(header: FZBHeader): Uint8Array {
    const buffer = new ArrayBuffer(24); // 4 + 4 + 4 + 4 + 4 + 4 bytes
    const view = new DataView(buffer);
    const bytes = new Uint8Array(buffer);

    // Magic bytes
    bytes.set(header.magic, 0);

    // Version (4 bytes, little-endian)
    view.setUint32(4, header.version, true);

    // Flags (4 bytes, little-endian)
    view.setUint32(8, header.flags, true);

    // Metadata size (4 bytes, little-endian)
    view.setUint32(12, header.metadataSize, true);

    // Data size (4 bytes, little-endian)
    view.setUint32(16, header.dataSize, true);

    // Checksum (4 bytes, little-endian)
    view.setUint32(20, header.checksum, true);

    return bytes;
  }

  private async compressData(data: string): Promise<Uint8Array> {
    // Simple compression using TextEncoder for now
    // In a real implementation, this would use proper compression (gzip, brotli, etc.)
    const encoder = new TextEncoder();
    return encoder.encode(data);
  }

  private calculateCRC32(data: Uint8Array): number {
    // Simplified CRC32 calculation
    // In a real implementation, this would use a proper CRC32 algorithm
    let crc = 0;
    for (let i = 0; i < data.length; i++) {
      crc = (crc + data[i]) % 0xFFFFFFFF;
    }
    return crc;
  }

  private async computeHash(data: string): Promise<string> {
    // Simple hash function for now
    // In a real implementation, this would use SHA-256 or similar
    let hash = 0;
    for (let i = 0; i < data.length; i++) {
      const char = data.charCodeAt(i);
      hash = ((hash << 5) - hash) + char;
      hash = hash & hash; // Convert to 32-bit integer
    }
    return Math.abs(hash).toString(16);
  }

  /**
   * Decompile FZB binary back to experiment
   */
  async decompile(binary: Uint8Array): Promise<Experiment> {
    // Parse FZB header
    const header = this.parseHeader(binary);

    // Validate magic bytes
    if (!this.validateMagic(header.magic)) {
      throw new Error('Invalid FZB file: magic bytes mismatch');
    }

    // Validate version
    if (header.version !== ForgeScriptCompiler.FZB_VERSION) {
      throw new Error(`Unsupported FZB version: ${header.version}`);
    }

    // Extract and decompress data
    const dataStart = 24; // Header size
    const compressedData = binary.slice(dataStart, dataStart + header.dataSize);

    // Validate checksum
    const actualChecksum = this.calculateCRC32(compressedData);
    if (actualChecksum !== header.checksum) {
      throw new Error('FZB file corruption detected: checksum mismatch');
    }

    // Decompress data
    const jsonData = await this.decompressData(compressedData);

    // Parse and deserialize experiment
    const serialized = JSON.parse(jsonData);
    return Serializer.deserialize(serialized);
  }

  private parseHeader(binary: Uint8Array): FZBHeader {
    if (binary.length < 24) {
      throw new Error('Invalid FZB file: too small');
    }

    const view = new DataView(binary.buffer, binary.byteOffset);

    return {
      magic: binary.slice(0, 4),
      version: view.getUint32(4, true),
      flags: view.getUint32(8, true),
      metadataSize: view.getUint32(12, true),
      dataSize: view.getUint32(16, true),
      checksum: view.getUint32(20, true),
    };
  }

  private validateMagic(magic: Uint8Array): boolean {
    if (magic.length !== 4) return false;
    for (let i = 0; i < 4; i++) {
      if (magic[i] !== ForgeScriptCompiler.FZB_MAGIC[i]) {
        return false;
      }
    }
    return true;
  }

  private async decompressData(data: Uint8Array): Promise<string> {
    // Simple decompression using TextDecoder for now
    const decoder = new TextDecoder();
    return decoder.decode(data);
  }

  /**
   * Get compiler version
   */
  static getVersion(): string {
    return ForgeScriptCompiler.VERSION;
  }

  /**
   * Check if a binary is a valid FZB file
   */
  static isFZBFile(binary: Uint8Array): boolean {
    if (binary.length < 4) return false;

    const magic = binary.slice(0, 4);
    for (let i = 0; i < 4; i++) {
      if (magic[i] !== ForgeScriptCompiler.FZB_MAGIC[i]) {
        return false;
      }
    }
    return true;
  }
}

// Export convenience functions
export async function compileExperiment(
  experiment: Experiment,
  options?: CompilerOptions
): Promise<CompilerResult> {
  const compiler = new ForgeScriptCompiler(options);
  return compiler.compile(experiment);
}

export async function decompileExperiment(binary: Uint8Array): Promise<Experiment> {
  const compiler = new ForgeScriptCompiler();
  return compiler.decompile(binary);
}

